import { useRef, useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import toast from "react-hot-toast";

import { useAuth } from "../../context/AuthContext";
import { updateProfile, uploadAvatar } from "../../services/profileService";
import styles from "./Profile.module.css";

const Profile = () => {
    const { user, updateUserState } = useAuth();
    const fileInputRef = useRef(null);
    const [uploading, setUploading] = useState(false);

    const {
        register,
        handleSubmit,
        reset,
        formState: { isDirty, isSubmitting },
    } = useForm({
        defaultValues: {
            fullName: "",
            username: "",
            email: "",
            phone: "",
            country: "",
            bio: "",
        },
    });

    // Sync form values on user load
    useEffect(() => {
        if (user) {
            reset({
                fullName: user.fullName || "",
                username: user.username || "",
                email: user.email || "",
                phone: user.phone || "",
                country: user.country || "",
                bio: user.bio || "",
            });
        }
    }, [user, reset]);

    const onSubmit = async (data) => {
        try {
            const res = await updateProfile({
                fullName: data.fullName,
                phone: data.phone,
                country: data.country,
                bio: data.bio,
            });
            updateUserState(res.user);
            toast.success("Profile updated successfully! ✨");
        } catch (error) {
            toast.error(error.message);
        }
    };

    const handleAvatarClick = () => {
        fileInputRef.current?.click();
    };

    const handleFileChange = async (e) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const formData = new FormData();
        formData.append("avatar", file);

        setUploading(true);
        try {
            const res = await uploadAvatar(formData);
            updateUserState({ avatar: res.avatar });
            toast.success("Avatar updated successfully! 📷");
        } catch (error) {
            toast.error(error.message);
        } finally {
            setUploading(false);
        }
    };

    if (!user) {
        return (
            <div className="global-loader-container">
                <div className="global-loader"></div>
            </div>
        );
    }

    return (
        <div className={styles.container}>
            <div className={styles.card}>
                <div className={styles.header}>
                    <div className={styles.avatarWrapper} onClick={handleAvatarClick}>
                        <img
                            src={user.avatar || "https://cdn-icons-png.flaticon.com/512/3135/3135715.png"}
                            alt="Avatar"
                            className={styles.avatar}
                        />
                        <div className={styles.avatarOverlay}>
                            {uploading ? "Uploading..." : "Change Photo"}
                        </div>
                        <input
                            type="file"
                            ref={fileInputRef}
                            style={{ display: "none" }}
                            accept="image/*"
                            onChange={handleFileChange}
                        />
                    </div>
                    <div className={styles.titleSection}>
                        <h1>{user.fullName}</h1>
                        <p>@{user.username} • Traveler</p>
                    </div>
                </div>

                <form onSubmit={handleSubmit(onSubmit)} className={styles.formGrid}>
                    <div className={styles.inputGroup}>
                        <label>Username (Read-Only)</label>
                        <input type="text" {...register("username")} disabled />
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Email (Read-Only)</label>
                        <input type="email" {...register("email")} disabled />
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Full Name</label>
                        <input
                            type="text"
                            placeholder="John Doe"
                            {...register("fullName", { required: "Full name is required" })}
                        />
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Phone Number</label>
                        <input type="text" placeholder="+1 (555) 019-2834" {...register("phone")} />
                    </div>

                    <div className={styles.inputGroup}>
                        <label>Home Country</label>
                        <input type="text" placeholder="France" {...register("country")} />
                    </div>

                    <div className={`${styles.inputGroup} ${styles.fullWidth}`}>
                        <label>Bio</label>
                        <textarea
                            placeholder="Tell us about your traveling style..."
                            {...register("bio")}
                        />
                    </div>

                    <div className={styles.fullWidth}>
                        <button
                            type="submit"
                            className={styles.saveBtn}
                            disabled={!isDirty || isSubmitting}
                        >
                            {isSubmitting ? "Saving Changes..." : "Save Profile Details"}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default Profile;
